    let left = 0;
    let right = edges[edges.length - 1][2];
    let result = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const uf = new UnionFind(n);
        for (const [u, v, time] of edges) {
            if (time > mid) {
                uf.union(u, v);
            }
        }
        if (uf.getComponents() >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}

